class FenwickTree {
    constructor(size) {
        this.n = size;
        this.tree = new Array(this.n + 1).fill(0);
    }

    update(index, delta) {
        index += 1; // convert to 1-based
        while (index <= this.n) {
            this.tree[index] += delta;
            index += index & -index;
        }
    }

    query(index) {
        index += 1; // convert to 1-based
        let res = 0;
        while (index > 0) {
            res += this.tree[index];
            index -= index & -index;
        }
        return res;
    }

    rangeQuery(l, r) {
        return this.query(r) - this.query(l - 1);
    }
}

